import{_ as i,o as e,c as l,a9 as t}from"./chunks/framework.STMWz9Nm.js";const s=JSON.parse('{"title":"状态管理与Checkpoint","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/10-Flink学习/04-状态管理与Checkpoint.md","filePath":"语言/java/10-Flink学习/04-状态管理与Checkpoint.md","lastUpdated":1776149370000}'),n={name:"语言/java/10-Flink学习/04-状态管理与Checkpoint.md"};function r(h,a,o,c,_,d){return e(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="状态管理与checkpoint" tabindex="-1">状态管理与Checkpoint <a class="header-anchor" href="#状态管理与checkpoint" aria-label="Permalink to “状态管理与Checkpoint”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>状态管理是 Flink 维护流计算上下文的能力，checkpoint 用于在失败时恢复一致状态。<br> 这是 Flink 区别于很多简单流式框架的核心优势之一。</p><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>没有状态，就很难做复杂流计算；没有 checkpoint，就很难保证容错和一致性。<br> 理解这两者，是真正掌握 Flink 的关键。</p><h2 id="_3-核心内容" tabindex="-1">3. 核心内容 <a class="header-anchor" href="#_3-核心内容" aria-label="Permalink to “3. 核心内容”">​</a></h2><ul><li>Keyed State</li><li>Operator State</li><li>State Backend 基本认知</li><li>Checkpoint</li><li>Savepoint</li><li>状态一致性</li></ul><h2 id="_4-学习重点" tabindex="-1">4. 学习重点 <a class="header-anchor" href="#_4-学习重点" aria-label="Permalink to “4. 学习重点”">​</a></h2><ul><li>理解状态不是临时变量，而是持续计算上下文</li><li>理解 checkpoint 用于容错恢复</li><li>理解 savepoint 更偏向可控迁移和升级</li></ul><h2 id="_5-常见问题" tabindex="-1">5. 常见问题 <a class="header-anchor" href="#_5-常见问题" aria-label="Permalink to “5. 常见问题”">​</a></h2><ul><li>不清楚状态会占用多少资源</li><li>checkpoint 开了却不了解恢复语义</li><li>把 savepoint 和 checkpoint 完全混为一谈</li></ul><h2 id="_6-练习建议" tabindex="-1">6. 练习建议 <a class="header-anchor" href="#_6-练习建议" aria-label="Permalink to “6. 练习建议”">​</a></h2><ul><li>写一个带状态的流式统计示例</li><li>总结 checkpoint 和 savepoint 的区别</li><li>结合故障恢复流程理解一致性保障</li></ul><h2 id="_7-自测问题" tabindex="-1">7. 自测问题 <a class="header-anchor" href="#_7-自测问题" aria-label="Permalink to “7. 自测问题”">​</a></h2><ul><li>Flink 为什么必须有状态管理</li><li>checkpoint 主要解决什么问题</li><li>savepoint 更适合哪些场景</li></ul>',15)])])}const k=i(n,[["render",r]]);export{s as __pageData,k as default};
